describe('GET /api/tasks', () => {
  const mockTasks = [
    { id: 'task-1', title: 'Task 1', difficulty: 'easy', description: 'Desc 1', version: '1.0', status: 'draft' as const },
    { id: 'task-2', title: 'Task 2', difficulty: 'medium', description: 'Desc 2', version: '1.0', status: 'review' as const },
    { id: 'task-3', title: 'Task 3', difficulty: 'hard', description: 'Desc 3', version: '1.0', status: 'published' as const },
    { id: 'task-4', title: 'Task 4', difficulty: 'medium', description: 'Desc 4', version: '1.0', status: 'published' as const },
  ];

  it('should return all tasks when no filters provided', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(4);
    expect(data.tasks).toHaveLength(4);
  });

  it('should filter tasks by difficulty', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=medium');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(2);
    expect(data.tasks.every((t: { difficulty: string }) => t.difficulty === 'medium')).toBe(true);
  });

  it('should filter tasks by status', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=published');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(2);
    expect(data.tasks.every((t: { status: string }) => t.status === 'published')).toBe(true);
  });

  it('should ignore invalid status values', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?status=invalid');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(4);
    expect(data.tasks).toHaveLength(4);
  });

  it('should filter by both difficulty and status', async () => {
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    vi.mocked(getTasks).mockResolvedValue(mockTasks as any);

    const request = new NextRequest('http://localhost/api/tasks?difficulty=medium&status=published');
    const response = await tasksHandler(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.count).toBe(1);
    expect(data.tasks[0].id).toBe('task-4');
  });
});

